#include<bits/stdc++.h>
using namespace std;
#define int long long
const int N=5e5+5;
int n,m,p,k,ans,a[N],tt,mx,cnt;

signed main(){
	cin>>n>>m>>k>>p;
	if(p>n*m||k<p){
		cout<<"NO\n";
		return 0;
	}
	int x=k/n,y=k%n;
	for(int i=1;i<=n;i++){
		if(y>0){
			a[i]=x+1;
			y--;
		}else{
			a[i]=x;
		}
		mx=max(mx,a[i]);
	}
	for(int i=1;i<=n;i++){
		if(a[i]==mx){
			cnt++;
		}
	}
	if(cnt==p){
		cout<<"YES\n";
		for(int i=1;i<=n;i++){
			cout<<a[i]<<" "<<m-a[i]<<"\n";
		}
	}else{
		cout<<"NO\n";
	}
	return 0;
}
